use serde::Serialize;

#[cfg(feature = "bcinr")]
use bcinr_logic::swar_str;

/// A single finding from the analyzer, with span relative to input.
#[derive(Debug, Clone, PartialEq, Eq, Serialize)]
pub struct RawFinding {
    pub code: String,
    pub message: String,
    pub span: (usize, usize),
}

/// Detection rule: code + patterns + message prefix
#[derive(Debug, Clone)]
pub struct Rule {
    pub code: &'static str,
    pub patterns: Vec<String>,
    pub message_prefix: &'static str,
}

impl Rule {
    pub fn new(code: &'static str, patterns: Vec<String>, message_prefix: &'static str) -> Self {
        Self {
            code,
            patterns,
            message_prefix,
        }
    }
}

/// Naive fallback: substring matching for when bcinr is not enabled.
fn analyze_rule_naive(input: &str, rule: &Rule, findings: &mut Vec<RawFinding>) {
    for pattern in &rule.patterns {
        if pattern.is_empty() {
            continue;
        }
        let mut start = 0;
        while let Some(pos) = input[start..].find(pattern.as_str()) {
            let abs = start + pos;
            findings.push(RawFinding {
                code: rule.code.to_string(),
                message: format!("{}: {pattern}", rule.message_prefix),
                span: (abs, abs + pattern.len()),
            });
            start = abs + pattern.len();
        }
    }
}

/// SIMD-accelerated pattern matching using bcinr-logic primitives.
/// Uses swar_str for byte-level operations and SIMD-friendly string scanning.
#[cfg(feature = "bcinr")]
fn analyze_rule_bcinr(input: &str, rule: &Rule, findings: &mut Vec<RawFinding>) {
    // Use bcinr-logic's swar_str for efficient byte scanning
    for pattern in &rule.patterns {
        if pattern.is_empty() {
            continue;
        }
        analyze_pattern_bcinr(input, pattern, rule.code, &rule.message_prefix, findings);
    }
}

/// Pattern search using bcinr-logic::swar_str for SIMD-optimized byte operations.
/// For single-byte patterns, leverages SWAR (SIMD Within A Register) techniques.
#[cfg(feature = "bcinr")]
fn analyze_pattern_bcinr(
    input: &str,
    pattern: &str,
    code: &str,
    message_prefix: &str,
    findings: &mut Vec<RawFinding>,
) {
    if pattern.len() == 1 {
        // Use bcinr-logic's optimized single-byte search
        let target_byte = pattern.as_bytes()[0];
        let input_bytes = input.as_bytes();
        let mut pos = 0;

        while let Some(offset) = swar_str::find_first_byte_in_slice(&input_bytes[pos..], target_byte) {
            let abs = pos + offset;
            findings.push(RawFinding {
                code: code.to_string(),
                message: format!("{}: {pattern}", message_prefix),
                span: (abs, abs + pattern.len()),
            });
            pos = abs + pattern.len();
        }
    } else {
        // For multi-byte patterns, fall back to standard substring search
        // (bcinr doesn't provide multi-byte pattern matching)
        let mut start = 0;
        while let Some(pos) = input[start..].find(pattern) {
            let abs = start + pos;
            findings.push(RawFinding {
                code: code.to_string(),
                message: format!("{}: {pattern}", message_prefix),
                span: (abs, abs + pattern.len()),
            });
            start = abs + pattern.len();
        }
    }
}

/// CANDIDATE: frontmatter
///
/// A pure, deterministic analyzer over a fixed ruleset. Purity is essential:
/// the verifier re-runs `analyze` on the witness and must obtain identical findings.
pub trait ReplayableAnalyzer {
    fn version(&self) -> &str;
    fn rules(&self) -> &[Rule];

    /// Stable digest over the ruleset, binding receipts to the exact rules.
    /// Changing any pattern invalidates receipts computed under old rules.
    fn ruleset_digest(&self) -> String {
        let mut h = blake3::Hasher::new();
        h.update(b"lsp-max-rvd/frontmatter/v1\n");
        for rule in self.rules() {
            h.update(rule.code.as_bytes());
            h.update(b"\n");
            for p in &rule.patterns {
                h.update(p.as_bytes());
                h.update(b"\x00");
            }
            h.update(b"\n");
        }
        h.finalize().to_hex().to_string()
    }

    /// Scan input, returning findings in deterministic order (by start, then code).
    /// Spans are relative to input.
    fn analyze(&self, input: &str) -> Vec<RawFinding> {
        let mut findings = Vec::new();
        for rule in self.rules() {
            #[cfg(feature = "bcinr")]
            {
                // Use SIMD-accelerated pattern matching when available
                analyze_rule_bcinr(input, rule, &mut findings);
            }
            #[cfg(not(feature = "bcinr"))]
            {
                // Fallback: naive substring matching
                analyze_rule_naive(input, rule, &mut findings);
            }
        }
        findings.sort_by(|a, b| a.span.0.cmp(&b.span.0).then(a.code.cmp(&b.code)));
        findings
    }
}

/// CANDIDATE: frontmatter implementation
pub struct FrontmatterAnalyzer {
    version: String,
    rules: Vec<Rule>,
}

impl FrontmatterAnalyzer {
    pub fn new() -> Self {
        Self {
            version: format!("frontmatter-rvd-{}", env!("CARGO_PKG_VERSION")),
            rules: agent_frontmatter_rules(),
        }
    }

    /// Construct an analyzer over an explicit ruleset (used in tests).
    pub fn with_rules(version: impl Into<String>, rules: Vec<Rule>) -> Self {
        Self {
            version: version.into(),
            rules,
        }
    }
}

impl Default for FrontmatterAnalyzer {
    fn default() -> Self {
        Self::new()
    }
}

impl ReplayableAnalyzer for FrontmatterAnalyzer {
    fn version(&self) -> &str {
        &self.version
    }
    fn rules(&self) -> &[Rule] {
        &self.rules
    }
}


